SELECT "SHIPPED" AS LineStatus, Item.[Trademark Code], Item.[Collection Code], Item.[Season Code], Item.[Line Code] AS LineCode, Item.[Product Family], Item.[Product Sex], Item.No_ AS Article, [Sales Line].[Constant Variable Code] AS Color, [Sales Line].[Promised Delivery Date] AS PromisedDeliveryDate, [Sales Line].[Requested Delivery Date] AS RequestedDeliveryDate, [Sales Shipment Header].[Posting Date] AS DeliveryDate, [Sales Shipment Header].No_ AS DeliverytNumber, [DDT_Picking Header].[Posted no_], [Sales Line].[Document No_] AS OrderNumber, [Sales Line].[Line No_] AS OrderLine, [Sales Header].[KIMO_FASHION SO No_], [Sales Line].Reference, [Sales Line].[Customer Order Ref_], [Sales Line].[assortment code] AS AssortmentCode, Val([Sales Shipment Line.Quantity (Base)]) AS DeliveryQuantity, Val([Sales Shipment Line.No_ of pairs]) AS DeliveryPairs, Val([Sales Line.Line Amount])/Val([Sales Line.quantity])*Val([Sales Shipment Line.quantity]) AS DeliveryValue, [Sales Line].[Document Type], [Sales Line].[Delete Reason], Item.[Description 2], [Sales Line].[Sales_Purchase Status Code] AS CodStatusVendAcq, [Sales Line].[Sales_Purchase Status - Item] AS CodStatusVendAcqArticolo, Item.[Sold Out], Item.[Sold Out Date], Item.[Sales_Purchase Status Date], Val([Sales Line.line discount _]) AS LineDiscount, Val([Sales Header.Invoice Discount Value]) AS InvoiceDiscount, IIf([Sales Header.Order Type]=1,"Riass.",IIf([Sales Header.order type]=2,"Pronto",IIf([Sales Header.order type]=3,"Stock",IIf([Sales Header.order type]=4,"Sost.",IIf([Sales Header.order type]=0,"Progr","?"))))) AS OrderType, Item.[advertising material]
FROM (((([Sales Shipment Line] INNER JOIN [Sales Shipment Header] ON [Sales Shipment Line].[Document No_] = [Sales Shipment Header].No_) INNER JOIN [Sales Line] ON ([Sales Shipment Line].[Order Line No_] = [Sales Line].[Line No_]) AND ([Sales Shipment Line].[Order No_] = [Sales Line].[Document No_])) INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) INNER JOIN Item ON [Sales Line].No_ = Item.No_) LEFT JOIN [DDT_Picking Header] ON [Sales Shipment Header].[DDT No_] = [DDT_Picking Header].No_
WHERE (((Item.[Season Code])=[filtroStagione]) AND ((Val([Sales Shipment Line.Quantity (Base)]))<>0) AND (([Sales Line].[Document Type])=1) AND (([Sales Line].[Delete Reason])="") AND (([Sales Line].Type)=20));

